import { useState, useEffect, useCallback } from 'react';
import secureStorage from '../utils/secureStorage';

export const useSecureStorage = (key, initialValue = null) => {
  const [storedValue, setStoredValue] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadValue = async () => {
      try {
        setLoading(true);
        const value = await secureStorage.getItem(key);
        setStoredValue(value || initialValue);
        setError(null);
      } catch (err) {
        setError(err);
        console.error('Error loading secure storage value:', err);
      } finally {
        setLoading(false);
      }
    };

    loadValue();
  }, [key]);

  const setValue = useCallback(async (value) => {
    try {
      setLoading(true);
      await secureStorage.setItem(key, value);
      setStoredValue(value);
      setError(null);
      return true;
    } catch (err) {
      setError(err);
      console.error('Error setting secure storage value:', err);
      return false;
    } finally {
      setLoading(false);
    }
  }, [key]);

  const removeValue = useCallback(async () => {
    try {
      setLoading(true);
      await secureStorage.removeItem(key);
      setStoredValue(initialValue);
      setError(null);
      return true;
    } catch (err) {
      setError(err);
      console.error('Error removing secure storage value:', err);
      return false;
    } finally {
      setLoading(false);
    }
  }, [key, initialValue]);

  return { storedValue, setValue, removeValue, loading, error };
};

// hooks/useAuth.js
import { useState, useEffect } from 'react';
import { authService } from '../services/authService';
import secureStorage from '../utils/secureStorage';

export const useAuth = () => {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    const loadAuthData = async () => {
      try {
        const [storedToken, storedUser] = await Promise.all([
          secureStorage.getAuthToken(),
          secureStorage.getUserProfile(),
        ]);

        if (storedToken && storedUser) {
          setToken(storedToken);
          setUser(storedUser);
          setIsAuthenticated(true);
        }
      } catch (error) {
        console.error('Error loading auth data:', error);
      } finally {
        setLoading(false);
      }
    };

    loadAuthData();
  }, []);

  const login = async (credentials) => {
    try {
      setLoading(true);
      const data = await authService.login(credentials);
      setToken(data.token);
      setUser(data.user);
      setIsAuthenticated(true);
      return data;
    } catch (error) {
      console.error('Login error:', error);
      throw error;
    } finally {
      setLoading(false);
    }
  };

  const logout = async () => {
    try {
      setLoading(true);
      await authService.logout();
      setToken(null);
      setUser(null);
      setIsAuthenticated(false);
    } catch (error) {
      console.error('Logout error:', error);
      throw error;
    } finally {
      setLoading(false);
    }
  };

  return {
    user,
    token,
    loading,
    isAuthenticated,
    login,
    logout,
  };
};

