// App.js
import React, { useEffect, useState } from 'react';
import { View, Text, Button, TextInput, StyleSheet, ActivityIndicator } from 'react-native';
import { useAuth } from './hooks/useAuth';
import { paymentService } from './services/paymentService';
import secureStorage from './utils/secureStorage';

const App = () => {
  const { user, isAuthenticated, login, logout, loading } = useAuth();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = async () => {
    try {
      await login({ email, password });
    } catch (error) {
      console.error('Login failed:', error);
    }
  };

  const handleLogout = async () => {
    try {
      await logout();
    } catch (error) {
      console.error('Logout failed:', error);
    }
  };

  const handleSavePayment = async () => {
    try {
      await paymentService.savePaymentMethod({
        cardNumber: '4111111111111111',
        cardType: 'Visa',
        expiryMonth: '12',
        expiryYear: '2025',
        billingAddress: '123 Main St',
      });
      console.log('Payment method saved');
    } catch (error) {
      console.error('Save payment failed:', error);
    }
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      {!isAuthenticated ? (
        <View style={styles.loginContainer}>
          <Text style={styles.title}>Login</Text>
          <TextInput
            style={styles.input}
            placeholder="Email"
            value={email}
            onChangeText={setEmail}
            autoCapitalize="none"
          />
          <TextInput
            style={styles.input}
            placeholder="Password"
            value={password}
            onChangeText={setPassword}
            secureTextEntry
          />
          <Button title="Login" onPress={handleLogin} />
        </View>
      ) : (
        <View style={styles.profileContainer}>
          <Text style={styles.title}>Welcome, {user?.name || 'User'}</Text>
          <Button title="Save Payment Method" onPress={handleSavePayment} />
          <Button title="Logout" onPress={handleLogout} />
        </View>
      )}
    </View>
  );
};

